  8→use std::path::Path;
  9→use std::sync::Arc;
 10→use std::time::Duration;
 11→
 12→use anyhow::{Context, Result};
 13→use libsql::{Builder, Connection, Database};
 14→
 15→/// Connection mode for the database handle.
 16→#[derive(Clone, Copy, PartialEq)]
 17→enum DbMode {
 18→    /// Local SQLite file or in-memory database.
 19→    Local,
 20→    /// Turso embedded replica with local cache — supports sync().
 21→    EmbeddedReplica,
 22→    /// Pure remote HTTP connection to Turso — no local cache, no sync().
 23→    Remote,
 24→}
 25→
 26→/// Async database handle wrapping a libsql Database.
 27→///
 28→/// Supports three modes:
 29→/// - **Local SQLite** (dev/offline fallback)
 30→/// - **Turso embedded replica** with local cache and sync
 31→/// - **Turso remote HTTP** (pure HTTP, no local cache — fallback when replica handshake fails)
 32→#[derive(Clone)]
 33→pub struct DbHandle {
 34→    db: Arc<Database>,
 35→    /// Shared connection used for all operations.
 36→    /// libsql's `:memory:` databases create a new database per `connect()` call,
 37→    /// so we keep one connection alive and reuse it everywhere.
 38→    ///
 39→    /// Safety: libsql connections are internally synchronized (serialized via mutex),
 40→    /// so sharing a single `Connection` behind `Arc` is safe for concurrent use
 41→    /// across multiple tokio tasks.
 42→    conn: Arc<Connection>,
 43→    mode: DbMode,
 44→}
 45→
 46→impl DbHandle {
 47→    /// Open a local-only SQLite database at the given path.
 48→    pub async fn new_local(path: &Path) -> Result<Self> {
 49→        let path_str = path.to_string_lossy().to_string();
 50→        let db = Builder::new_local(&path_str)
 51→            .build()
 52→            .await
 53→            .context("Failed to open local SQLite database")?;
 54→        Self::from_db(db, DbMode::Local).await
 55→    }
 56→
 57→    /// Open a Turso embedded replica with local file cache.
 58→    /// Falls back to pure remote (HTTP) mode if the embedded replica handshake fails.
 59→    pub async fn new_remote_replica(
 60→        local_path: &Path,
 61→        url: &str,
 62→        token: &str,
 63→    ) -> Result<Self> {
 64→        let path_str = local_path.to_string_lossy().to_string();
 65→        let replica_result = Builder::new_remote_replica(
 66→            &path_str,
 67→            url.to_string(),
 68→            token.to_string(),
 69→        )
 70→        .sync_interval(Duration::from_secs(60))
 71→        .read_your_writes(true)
 72→        .build()
 73→        .await;
 74→
 75→        match replica_result {
 76→            Ok(db) => {
 77→                // Try initial sync; if it fails, fall back to remote mode
 78→                match db.sync().await {
 79→                    Ok(_) => {
 80→                        eprintln!("[db] Embedded replica synced successfully");
 81→                        let conn = db.connect().context("Failed to get initial connection")?;
 82→                        init_pragmas(&conn, DbMode::EmbeddedReplica).await?;
 83→                        migrations::run_migrations(&conn).await?;
 84→                        Ok(Self {
 85→                            db: Arc::new(db),
 86→                            conn: Arc::new(conn),
 87→                            mode: DbMode::EmbeddedReplica,
 88→                        })
 89→                    }
 90→                    Err(e) => {
 91→                        eprintln!("[db] Embedded replica sync failed ({e}), falling back to remote HTTP mode");
 92→                        // Clean up stale replica files
 93→                        let _ = std::fs::remove_file(&path_str);
 94→                        let _ = std::fs::remove_file(format!("{path_str}-shm"));
 95→                        let _ = std::fs::remove_file(format!("{path_str}-wal"));
 96→                        Self::new_remote(url, token).await
 97→                    }
 98→                }
 99→            }
100→            Err(e) => {
101→                eprintln!("[db] Failed to open embedded replica ({e}), falling back to remote HTTP mode");
102→                Self::new_remote(url, token).await
103→            }
104→        }
105→    }
