480→/// Set WAL mode, busy timeout, and enable foreign keys.
481→/// Only applies to local databases — Turso (both embedded replica and remote HTTP)
482→/// manages these internally and doesn't support PRAGMA statements over HTTP.
483→async fn init_pragmas(conn: &Connection, mode: DbMode) -> Result<()> {
484→    if mode != DbMode::Local {
485→        return Ok(());
486→    }
487→    // journal_mode and busy_timeout return rows, so use query() instead of execute()
488→    conn.query("PRAGMA journal_mode=WAL", ())
489→        .await
490→        .context("Failed to set WAL mode")?;
491→    conn.query("PRAGMA busy_timeout=5000", ())
492→        .await
493→        .context("Failed to set busy_timeout")?;
494→    conn.execute("PRAGMA foreign_keys=ON", ())
495→        .await
496→        .context("Failed to enable foreign keys")?;
497→    Ok(())
498→}
