529→/// Run integrity check on startup. Logs warning but does not fail.
530→pub async fn health_check(conn: &Connection) {
531→    match conn.query("PRAGMA integrity_check", ()).await {
532→        Ok(mut rows) => {
533→            match rows.next().await {
534→                Ok(Some(row)) => {
535→                    match row.get::<String>(0) {
536→                        Ok(result) if result == "ok" => { /* healthy */ }
537→                        Ok(result) => {
538→                            eprintln!("[db] WARNING: database integrity check failed: {result}");
539→                        }
540→                        Err(e) => {
541→                            eprintln!("[db] WARNING: could not read integrity check result: {e}");
542→                        }
543→                    }
544→                }
545→                Ok(None) => {
546→                    eprintln!("[db] WARNING: integrity check returned no rows");
547→                }
548→                Err(e) => {
