 13→/// Run all pending migrations.
 14→/// Uses a `_migrations` table to track schema version (works across local SQLite and Turso HTTP).
 15→pub async fn run_migrations(conn: &Connection) -> Result<()> {
 16→    ensure_migrations_table(conn).await?;
 17→    let current_version = get_schema_version(conn).await?;
 18→
 19→    // Bootstrap: if _migrations table is empty but other tables exist (pre-migration DB),
 20→    // detect existing schema and set version accordingly.
 21→    if current_version == 0 {
