 23→        if bootstrapped > 0 {
 24→            eprintln!("[db] Bootstrapped existing database at migration version {bootstrapped}");
 25→            return run_from_version(conn, bootstrapped).await;
 26→        }
 27→    }
 28→
 29→    run_from_version(conn, current_version).await
 30→}
