106→pub async fn update_issue(
107→    conn: &Connection,
108→    id: i64,
109→    title: Option<&str>,
110→    description: Option<&str>,
111→    priority: Option<&str>,
112→    labels: Option<&str>,
113→) -> Result<Issue> {
114→    if let Some(p) = priority {
115→        Priority::from_str(p)
116→            .map_err(|e| anyhow::anyhow!(e))
117→            .context("Invalid priority value")?;
118→    }
119→
120→    let tx = conn.transaction().await.context("Failed to begin transaction")?;
121→
122→    if let Some(t) = title {
123→        tx.execute(
124→            "UPDATE issues SET title = ?1, updated_at = datetime('now') WHERE id = ?2",
125→            (t, id),
126→        )
127→        .await
128→        .context("Failed to update issue title")?;
129→    }
130→    if let Some(d) = description {
131→        tx.execute(
132→            "UPDATE issues SET description = ?1, updated_at = datetime('now') WHERE id = ?2",
133→            (d, id),
134→        )
135→        .await
136→        .context("Failed to update issue description")?;
137→    }
138→    if let Some(p) = priority {
139→        tx.execute(
140→            "UPDATE issues SET priority = ?1, updated_at = datetime('now') WHERE id = ?2",
141→            (p, id),
142→        )
143→        .await
144→        .context("Failed to update issue priority")?;
145→    }
146→    if let Some(l) = labels {
147→        tx.execute(
148→            "UPDATE issues SET labels = ?1, updated_at = datetime('now') WHERE id = ?2",
149→            (l, id),
150→        )
151→        .await
152→        .context("Failed to update issue labels")?;
153→    }
154→
155→    tx.commit().await.context("Failed to commit issue update")?;
156→    get_issue(conn, id)
157→        .await?
158→        .context("Issue not found after update")
159→}
