189→pub async fn create_issue_from_github(
190→    conn: &Connection,
191→    project_id: i64,
192→    title: &str,
193→    description: &str,
194→    github_issue_number: i64,
195→) -> Result<Option<Issue>> {
196→    let mut rows = conn
197→        .query(
198→            "SELECT COUNT(*) > 0 FROM issues WHERE project_id = ?1 AND github_issue_number = ?2",
199→            (project_id, github_issue_number),
200→        )
201→        .await?;
202→    let exists: bool = match rows.next().await? {
203→        Some(row) => {
204→            let count: i64 = row.get(0)?;
205→            count != 0
206→        }
207→        None => false,
208→    };
209→    if exists {
210→        return Ok(None);
211→    }
212→
213→    let mut rows = conn
214→        .query(
215→            "SELECT COALESCE(MAX(position), -1) FROM issues WHERE project_id = ?1 AND column_name = 'backlog'",
216→            [project_id],
217→        )
218→        .await?;
219→    let max_pos: i32 = match rows.next().await? {
220→        Some(row) => row.get(0)?,
221→        None => -1,
222→    };
223→
224→    conn.execute(
225→        "INSERT INTO issues (project_id, title, description, column_name, position, github_issue_number) VALUES (?1, ?2, ?3, 'backlog', ?4, ?5)",
226→        libsql::params![project_id, title, description, max_pos + 1, github_issue_number],
227→    )
228→    .await
229→    .context("Failed to insert github issue")?;
230→    let id = conn.last_insert_rowid();
231→    get_issue(conn, id).await
232→}
