234→pub async fn get_board(conn: &Connection, project_id: i64) -> Result<BoardView> {
235→    let project = super::projects::get_project(conn, project_id)
236→        .await?
237→        .context("Project not found for board view")?;
238→
239→    let all_issues = list_issues(conn, project_id).await?;
240→
241→    let column_order = [
242→        IssueColumn::Backlog,
243→        IssueColumn::Ready,
244→        IssueColumn::InProgress,
245→        IssueColumn::InReview,
246→        IssueColumn::Done,
247→    ];
248→
249→    let mut columns = Vec::new();
250→    for col in &column_order {
251→        let mut col_issues: Vec<IssueWithStatus> = all_issues
252→            .iter()
253→            .filter(|i| i.column == *col)
254→            .map(|i| IssueWithStatus {
255→                issue: i.clone(),
256→                active_run: None,
257→            })
258→            .collect();
259→
260→        col_issues.sort_by_key(|iws| iws.issue.position);
261→
262→        for iws in &mut col_issues {
263→            let sql = format!(
264→                "SELECT {} FROM pipeline_runs WHERE issue_id = ?1 AND status IN ('queued', 'running') ORDER BY id DESC LIMIT 1",
265→                RUN_COLS
266→            );
267→            let mut rows = conn.query(&sql, [iws.issue.id]).await?;
268→            if let Some(row) = rows.next().await? {
269→                iws.active_run = Some(row_to_pipeline_run(&row)?);
270→            }
271→        }
272→
273→        columns.push(ColumnView {
274→            name: col.clone(),
275→            issues: col_issues,
276→        });
277→    }
278→
279→    Ok(BoardView { project, columns })
280→}
