282→pub async fn get_issue_detail(conn: &Connection, id: i64) -> Result<Option<IssueDetail>> {
283→    let issue = match get_issue(conn, id).await? {
284→        Some(i) => i,
285→        None => return Ok(None),
286→    };
287→
288→    let sql = format!(
289→        "SELECT {} FROM pipeline_runs WHERE issue_id = ?1 ORDER BY id",
290→        RUN_COLS
291→    );
292→    let mut rows = conn
293→        .query(&sql, [id])
294→        .await
295→        .context("Failed to query pipeline runs")?;
296→    let mut runs = Vec::new();
297→    while let Some(row) = rows.next().await? {
298→        let run = row_to_pipeline_run(&row)?;
299→        let phases = super::pipeline::get_pipeline_phases(conn, run.id).await?;
300→        runs.push(PipelineRunDetail { run, phases });
301→    }
302→
303→    Ok(Some(IssueDetail { issue, runs }))
304→}
