 41→pub async fn create_issue(
 42→    conn: &Connection,
 43→    project_id: i64,
 44→    title: &str,
 45→    description: &str,
 46→    column: &IssueColumn,
 47→) -> Result<Issue> {
 48→    let tx = conn.transaction().await.context("Failed to begin transaction")?;
 49→    let mut rows = tx
 50→        .query(
 51→            "SELECT COALESCE(MAX(position), -1) FROM issues WHERE project_id = ?1 AND column_name = ?2",
 52→            (project_id, column.as_str()),
 53→        )
 54→        .await
 55→        .context("Failed to get max position")?;
 56→    let max_pos: i32 = match rows.next().await? {
 57→        Some(row) => row.get(0)?,
 58→        None => -1,
 59→    };
 60→    let position = max_pos + 1;
 61→    tx.execute(
 62→        "INSERT INTO issues (project_id, title, description, column_name, position) VALUES (?1, ?2, ?3, ?4, ?5)",
 63→        libsql::params![project_id, title, description, column.as_str(), position],
 64→    )
 65→    .await
 66→    .context("Failed to insert issue")?;
 67→    let id = tx.last_insert_rowid();
 68→    tx.commit().await.context("Failed to commit")?;
 69→    get_issue(conn, id)
 70→        .await?
 71→        .context("Issue not found after insert")
 72→}
