 74→pub async fn list_issues(conn: &Connection, project_id: i64) -> Result<Vec<Issue>> {
 75→    let sql = format!(
 76→        "SELECT {} FROM issues WHERE project_id = ?1 AND deleted_at IS NULL ORDER BY position",
 77→        ISSUE_COLS
 78→    );
 79→    let mut rows = conn
 80→        .query(&sql, [project_id])
 81→        .await
 82→        .context("Failed to query issues")?;
 83→    let mut issues = Vec::new();
 84→    while let Some(row) = rows.next().await? {
 85→        issues.push(row_to_issue(&row)?);
 86→    }
 87→    Ok(issues)
 88→}
