105→pub async fn update_issue(
106→    conn: &Connection,
107→    id: i64,
108→    title: Option<&str>,
109→    description: Option<&str>,
110→    priority: Option<&str>,
111→    labels: Option<&str>,
112→) -> Result<Issue> {
113→    if let Some(p) = priority {
114→        Priority::from_str(p)
115→            .map_err(|e| anyhow::anyhow!(e))
116→            .context("Invalid priority value")?;
117→    }
118→
119→    let tx = conn.transaction().await.context("Failed to begin transaction")?;
120→
121→    if let Some(t) = title {
122→        tx.execute(
123→            "UPDATE issues SET title = ?1, updated_at = datetime('now') WHERE id = ?2",
124→            (t, id),
125→        )
126→        .await
127→        .context("Failed to update issue title")?;
128→    }
129→    if let Some(d) = description {
130→        tx.execute(
131→            "UPDATE issues SET description = ?1, updated_at = datetime('now') WHERE id = ?2",
132→            (d, id),
133→        )
134→        .await
135→        .context("Failed to update issue description")?;
136→    }
137→    if let Some(p) = priority {
138→        tx.execute(
139→            "UPDATE issues SET priority = ?1, updated_at = datetime('now') WHERE id = ?2",
140→            (p, id),
141→        )
142→        .await
143→        .context("Failed to update issue priority")?;
144→    }
145→    if let Some(l) = labels {
146→        tx.execute(
147→            "UPDATE issues SET labels = ?1, updated_at = datetime('now') WHERE id = ?2",
148→            (l, id),
149→        )
150→        .await
151→        .context("Failed to update issue labels")?;
152→    }
153→
154→    tx.commit().await.context("Failed to commit issue update")?;
155→    get_issue(conn, id)
156→        .await?
157→        .context("Issue not found after update")
158→}
