188→pub async fn create_issue_from_github(
189→    conn: &Connection,
190→    project_id: i64,
191→    title: &str,
192→    description: &str,
193→    github_issue_number: i64,
194→) -> Result<Option<Issue>> {
195→    let tx = conn.transaction().await.context("Failed to begin transaction")?;
196→
197→    let mut rows = tx
198→        .query(
199→            "SELECT COUNT(*) > 0 FROM issues WHERE project_id = ?1 AND github_issue_number = ?2",
200→            (project_id, github_issue_number),
201→        )
202→        .await
203→        .context("Failed to check for existing github issue")?;
204→    let exists: bool = match rows.next().await? {
205→        Some(row) => {
206→            let count: i64 = row.get(0)?;
207→            count != 0
208→        }
209→        None => false,
210→    };
211→    if exists {
212→        return Ok(None);
213→    }
214→
215→    let mut rows = tx
216→        .query(
217→            "SELECT COALESCE(MAX(position), -1) FROM issues WHERE project_id = ?1 AND column_name = 'backlog'",
218→            [project_id],
219→        )
220→        .await
221→        .context("Failed to get max backlog position")?;
222→    let max_pos: i32 = match rows.next().await? {
223→        Some(row) => row.get(0)?,
224→        None => -1,
225→    };
226→
227→    tx.execute(
228→        "INSERT INTO issues (project_id, title, description, column_name, position, github_issue_number) VALUES (?1, ?2, ?3, 'backlog', ?4, ?5)",
229→        libsql::params![project_id, title, description, max_pos + 1, github_issue_number],
230→    )
231→    .await
232→    .context("Failed to insert github issue")?;
233→    let id = tx.last_insert_rowid();
234→    tx.commit().await.context("Failed to commit")?;
235→    get_issue(conn, id).await
236→}
