238→pub async fn get_board(conn: &Connection, project_id: i64) -> Result<BoardView> {
239→    let project = super::projects::get_project(conn, project_id)
240→        .await?
241→        .context("Project not found for board view")?;
242→
243→    let all_issues = list_issues(conn, project_id).await?;
244→
245→    let column_order = [
246→        IssueColumn::Backlog,
247→        IssueColumn::Ready,
248→        IssueColumn::InProgress,
249→        IssueColumn::InReview,
250→        IssueColumn::Done,
251→    ];
252→
253→    let mut columns = Vec::new();
254→    for col in &column_order {
255→        let mut col_issues: Vec<IssueWithStatus> = all_issues
256→            .iter()
257→            .filter(|i| i.column == *col)
258→            .map(|i| IssueWithStatus {
259→                issue: i.clone(),
260→                active_run: None,
261→            })
262→            .collect();
263→
264→        col_issues.sort_by_key(|iws| iws.issue.position);
265→
266→        for iws in &mut col_issues {
267→            let sql = format!(
268→                "SELECT {} FROM pipeline_runs WHERE issue_id = ?1 AND status IN ('queued', 'running') ORDER BY id DESC LIMIT 1",
269→                RUN_COLS
270→            );
271→            let mut rows = conn.query(&sql, [iws.issue.id]).await.context("Failed to query active pipeline run for issue")?;
272→            if let Some(row) = rows.next().await? {
273→                iws.active_run = Some(row_to_pipeline_run(&row)?);
274→            }
275→        }
276→
277→        columns.push(ColumnView {
278→            name: col.clone(),
279→            issues: col_issues,
280→        });
281→    }
282→
283→    Ok(BoardView { project, columns })
284→}
