286→pub async fn get_issue_detail(conn: &Connection, id: i64) -> Result<Option<IssueDetail>> {
287→    let issue = match get_issue(conn, id).await? {
288→        Some(i) => i,
289→        None => return Ok(None),
290→    };
291→
292→    let sql = format!(
293→        "SELECT {} FROM pipeline_runs WHERE issue_id = ?1 ORDER BY id",
294→        RUN_COLS
295→    );
296→    let mut rows = conn
297→        .query(&sql, [id])
298→        .await
299→        .context("Failed to query pipeline runs")?;
300→    let mut runs = Vec::new();
301→    while let Some(row) = rows.next().await? {
302→        let run = row_to_pipeline_run(&row)?;
303→        let phases = super::pipeline::get_pipeline_phases(conn, run.id).await?;
304→        runs.push(PipelineRunDetail { run, phases });
305→    }
306→
307→    Ok(Some(IssueDetail { issue, runs }))
308→}
